// // This module implements an 8-bit register with asynchronous reset and clock disable.
module Register8Bit (
    input clk,
    input rst,
    input enable,
    input [7:0] data_in,
    output reg [7:0] data_out
);
    always @(posedge clk) begin
        if (rst) begin
            data_out <= 8'b00000000;
        end else if (enable) begin
            data_out <= data_in;
        end
    end
endmodule
